import mongoose from 'mongoose';
import { BaseSchema } from './config/db.config.js';
import { TELEMETRY_COLLECTION, TRANSCODE_COLLECTION, QOE_COLLECTION, ADAPTATION_DECISIONS_COLLECTION, ADAPTATION_FEEDBACK_COLLECTION, ZK_PROOFS_COLLECTION, ZK_AUDIT_COLLECTION, } from './utils.js';
export const VMAF_COLLECTION = 'vmaf_scores';
export const TelemetryModel = mongoose.model(TELEMETRY_COLLECTION, BaseSchema, TELEMETRY_COLLECTION);
export const TranscodeEventModel = mongoose.model(TRANSCODE_COLLECTION, BaseSchema, TRANSCODE_COLLECTION);
export const QoeModel = mongoose.model(QOE_COLLECTION, BaseSchema, QOE_COLLECTION);
export const VMAFModel = mongoose.model(VMAF_COLLECTION, BaseSchema, VMAF_COLLECTION);
export const AdaptationDecisionModel = mongoose.model(ADAPTATION_DECISIONS_COLLECTION, BaseSchema, ADAPTATION_DECISIONS_COLLECTION);
export const AdaptationFeedbackModel = mongoose.model(ADAPTATION_FEEDBACK_COLLECTION, BaseSchema, ADAPTATION_FEEDBACK_COLLECTION);
export const ZkProofModel = mongoose.model(ZK_PROOFS_COLLECTION, BaseSchema, ZK_PROOFS_COLLECTION);
export const ZkAuditModel = mongoose.model(ZK_AUDIT_COLLECTION, BaseSchema, ZK_AUDIT_COLLECTION);
